//FILE *fin = freopen("in","r",stdin);
//FILE *fout = freopen("out","w",stdout);
const int R=int(1e6)+5,P=25,N=R,mod = int(1e9)+7;
int  F[R][P],LP[N];
inline void seive(){
  LP[1]=1;
  for(int i=2;i<N;i++){
    if(!LP[i])
      for(int j=i;j<N;j+=i)
        LP[j]=i;      
  }
}
inline void precalc()
{
  for(int i=0;i<R;i++) F[i][0] = 1; 
  for(int i=1;i<P;i++) F[0][i] = 2;
  for(int i=1;i<R;i++) 
   for(int j=1;j<P;j++)
     F[i][j] = (F[i][j-1] + F[i-1][j])%mod;
}
inline LL solve(int r,int n)
{
  LL ans=1;
  while(n!=1)
  {
      int cnt=0,p=LP[n];
      while(n%p==0) n/=p,cnt++;
      ans=(ans*F[r][cnt])%mod;
  }
  return ans;
}
int main()
{
  seive();precalc();
  int q;si(q);
  int r,n;
  while(q--)
  {
    si(r);si(n);
    lldout(solve(r,n));
  }
  return 0;
}


